import Foundation

// MARK: - Resolution

public enum MenuBarSegmentIssue: Equatable, Sendable {
    /// `.currentlyActive` was selected but no account for the vendor is flagged active.
    case noActiveAccount(vendor: Vendor)
    /// A specific account was selected but it's absent from the usages file.
    case accountNotFound(vendor: Vendor, email: AccountEmail)
    /// The target metric name is not present on the resolved account.
    case metricNotFound(metricName: String)
    /// The metric exists but its kind doesn't match the configured display variant
    /// (e.g. timeWindow display on a pay-as-you-go metric). Happens when the user
    /// changes the underlying metric kind externally.
    case metricKindMismatch
}

public struct ResolvedMenuBarSegment: Sendable {
    public let config: MenuBarSegmentConfig
    public let rendered: MenuBarSegment?
    public let issue: MenuBarSegmentIssue?

    public init(config: MenuBarSegmentConfig, rendered: MenuBarSegment?, issue: MenuBarSegmentIssue?) {
        self.config = config
        self.rendered = rendered
        self.issue = issue
    }
}

// MARK: - Resolver

/// Converts a `MenuBarSegmentConfig` + a snapshot of usage entries into either a
/// renderable `MenuBarSegment` or a structured issue that the Settings UI can
/// surface to the user.
public enum MenuBarSegmentResolver {

    public static func resolve(
        config: MenuBarSegmentConfig,
        entries: [VendorUsageEntry],
        now: Date
    ) -> ResolvedMenuBarSegment {
        let vendorEntries = entries.filter { $0.vendor == config.vendor }

        let entry: VendorUsageEntry?
        let resolveIssue: MenuBarSegmentIssue?
        switch config.account {
        case .currentlyActive:
            if let active = vendorEntries.first(where: { $0.isActive }) {
                entry = active
                resolveIssue = nil
            } else if vendorEntries.count == 1 {
                // No account is flagged active, but there is only one — treat it as implicitly active
                // so the user sees their data without having to wait for the monitor to sync.
                entry = vendorEntries[0]
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .noActiveAccount(vendor: config.vendor)
            }
        case .specific(let email):
            if let match = vendorEntries.first(where: { $0.account == email }) {
                entry = match
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .accountNotFound(vendor: config.vendor, email: email)
            }
        }

        guard let entry else {
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: resolveIssue)
        }

        guard let metric = entry.metrics.first(where: { metricName($0) == config.metricName }) else {
            return ResolvedMenuBarSegment(
                config: config,
                rendered: nil,
                issue: .metricNotFound(metricName: config.metricName)
            )
        }

        switch (metric, config.display) {
        case let (.timeWindow(_, resetAt, windowDuration, usagePercent), .timeWindow(display)):
            let segment = renderTimeWindow(
                display: display,
                vendor: config.vendor,
                resetAt: resetAt,
                windowDuration: windowDuration,
                usagePercent: usagePercent,
                now: now
            )
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        case let (.payAsYouGo(_, currentAmount, currency), .payAsYouGo):
            let segment = renderPayAsYouGo(currentAmount: currentAmount, currency: currency)
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        default:
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: .metricKindMismatch)
        }
    }

    private static func metricName(_ metric: UsageMetric) -> String? {
        switch metric {
        case .timeWindow(let name, _, _, _):   return name
        case .payAsYouGo(let name, _, _):      return name
        case .unknown:                         return nil
        }
    }

    // MARK: Rendering

    private static func renderTimeWindow(
        display: TimeWindowDisplay,
        vendor: Vendor,
        resetAt: ISODate?,
        windowDuration: DurationMinutes,
        usagePercent: UsagePercent,
        now: Date
    ) -> MenuBarSegment? {
        // Single source of truth shared with TimeWindowMetricRow — see
        // TimeWindowVisualState. Do NOT recompute isUnknown / tier locally.
        let state = TimeWindowVisualState(
            resetAt: resetAt,
            windowDuration: windowDuration,
            usagePercent: usagePercent,
            now: now
        )

        var parts: [String] = []
        if display.showLetter, !display.letter.isEmpty {
            parts.append(display.letter)
        }
        if state.isUnknown {
            // Both percent and remaining would otherwise be "???" — collapse
            // them into a single placeholder when at least one is shown, to
            // avoid the awkward "S ??? ???" double placeholder.
            if display.showPercent || display.showReset {
                parts.append("???")
            }
        } else {
            if display.showPercent {
                parts.append(formatUsagePercent(usagePercent, mode: display.percentDisplayMode))
            }
            if display.showReset, let resetAt {
                parts.append(formatRemainingTime(
                    resetAt: resetAt,
                    now: now,
                    hideMinutesWhenOverOneDay: display.hideResetMinutesWhenOverOneDay
                ))
            }
        }
        let text = parts.joined(separator: " ")

        let tier: ConsumptionTier? = display.showDot ? state.tier : nil

        // If the user turned every visible element off, there's nothing to render
        if text.isEmpty, !display.showDot, !display.showVendorIcon {
            return nil
        }

        let vendorIcon: Vendor? = display.showVendorIcon ? vendor : nil
        return MenuBarSegment(text: text, tier: tier, showDot: display.showDot, vendorIcon: vendorIcon)
    }

    private static func formatUsagePercent(_ usagePercent: UsagePercent, mode: UsagePercentDisplayMode) -> String {
        switch mode {
        case .consumed:
            return "\(usagePercent.rawValue)%"
        case .remaining:
            return "\(max(0, 100 - usagePercent.rawValue))%"
        }
    }

    private static func renderPayAsYouGo(currentAmount: Double, currency: String) -> MenuBarSegment {
        let amount = String(format: "%.2f", currentAmount)
        return MenuBarSegment(text: "\(amount) \(currency)", tier: nil, showDot: false)
    }
}

import Foundation

// MARK: - Remaining time formatting

private let secondsPerMinute = 60
private let secondsPerHour = 3600
private let secondsPerDay = 86400

/// Formats the remaining time until `resetAt` as a compact string (e.g. "2d 5h 13m").
/// Returns `"--"` when `resetAt` cannot be parsed, `"0m"` when the reset date has passed.
public func formatRemainingTime(resetAt: ISODate, now: Date, hideMinutesWhenOverOneDay: Bool = false) -> String {
    guard let resetDate = resetAt.date else { return "--" }
    let totalSeconds = Int(resetDate.timeIntervalSince(now))
    guard totalSeconds > 0 else { return "0m" }

    let days = totalSeconds / secondsPerDay
    let hours = (totalSeconds % secondsPerDay) / secondsPerHour
    let minutes = (totalSeconds % secondsPerHour) / secondsPerMinute

    if hideMinutesWhenOverOneDay, totalSeconds > secondsPerDay {
        let roundedHours = (totalSeconds + secondsPerHour / 2) / secondsPerHour
        let roundedDays = roundedHours / 24
        let remainingHours = roundedHours % 24

        var roundedParts: [String] = []
        if roundedDays > 0 { roundedParts.append("\(roundedDays)d") }
        if remainingHours > 0 { roundedParts.append("\(remainingHours)h") }
        return roundedParts.joined(separator: " ")
    }

    var parts: [String] = []
    if days > 0 { parts.append("\(days)d") }
    if hours > 0 { parts.append("\(hours)h") }
    if minutes > 0 || parts.isEmpty { parts.append("\(minutes)m") }
    return parts.joined(separator: " ")
}

// MARK: - Theoretical fraction

/// Fraction of the time window that has elapsed, clamped to 0...1.
/// Returns 0 when `resetAt` cannot be parsed or `windowDuration` is zero.
public func theoreticalFraction(resetAt: ISODate, windowDuration: DurationMinutes, now: Date) -> Double {
    guard let resetDate = resetAt.date else { return 0 }
    let windowSeconds = Double(windowDuration.rawValue) * 60
    guard windowSeconds > 0 else { return 0 }
    let windowStart = resetDate.addingTimeInterval(-windowSeconds)
    let elapsed = now.timeIntervalSince(windowStart)
    return min(max(elapsed / windowSeconds, 0), 1)
}

// MARK: - Reset date formatting

/// Formats the reset date relative to `now`:
/// - same calendar day → time only ("HH:mm")
/// - next calendar day → "tomorrow HH:mm"
/// - otherwise → "MMM d, HH:mm"
/// Returns "--" when `resetAt` cannot be parsed.
public func formatResetDate(_ resetAt: ISODate, now: Date) -> String {
    guard let resetDate = resetAt.date else { return "--" }
    let calendar = Calendar.current
    let today = calendar.startOfDay(for: now)
    let resetDay = calendar.startOfDay(for: resetDate)
    let timeString = ResetDateFormatting.timeFormatter.string(from: resetDate)
    if resetDay == today {
        return "@ \(timeString)"
    }
    let tomorrow = calendar.date(byAdding: .day, value: 1, to: today)!
    if resetDay == tomorrow {
        return "Tomorrow @ \(timeString)"
    }
    return ResetDateFormatting.dateTimeFormatter.string(from: resetDate)
}

// Singletons are safe: only called from @MainActor SwiftUI views
private enum ResetDateFormatting {
    static let timeFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateFormat = "HH:mm"
        return f
    }()

    static let dateTimeFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateFormat = "MMM d '@' HH:mm"
        return f
    }()
}

// MARK: - Consumption tier

/// Severity tiers for consumption ratio (actual / theoretical pace).
/// Ordered by severity so `Comparable` yields the worst tier via `max()`.
public enum ConsumptionTier: Int, Comparable, Sendable, CaseIterable {
    case comfortable  // < 0.7
    case onTrack      // [0.7, 0.9)
    case approaching  // [0.9, 1.0)
    case over         // [1.0, 1.2)
    case critical     // [1.2, 1.6)
    case exhausted    // >= 1.6

    public static func < (lhs: ConsumptionTier, rhs: ConsumptionTier) -> Bool {
        lhs.rawValue < rhs.rawValue
    }

    private static let comfortableUpperBound = 0.7
    private static let onTrackUpperBound = 0.9
    private static let approachingUpperBound = 1.0
    private static let overUpperBound = 1.2
    private static let criticalUpperBound = 1.6
}

/// Maps a consumption ratio to the appropriate severity tier.
public func consumptionTier(ratio: Double) -> ConsumptionTier {
    switch ratio {
    case ..<0.7:       return .comfortable
    case ..<0.9:       return .onTrack
    case ..<1.0:       return .approaching
    case ..<1.2:       return .over
    case ..<1.6:       return .critical
    default:           return .exhausted
    }
}

/// Computes the consumption ratio: how fast actual usage is relative to theoretical pace.
/// Returns `nil` when `theoreticalFraction` is zero or negative (window not started).
public func consumptionRatio(actualPercent: UsagePercent, theoreticalFraction: Double) -> Double? {
    guard theoreticalFraction > 0 else { return nil }
    return Double(actualPercent.rawValue) / (theoreticalFraction * 100.0)
}

// MARK: - Time-window visual state

/// Single source of truth for "what does this time-window metric look like
/// right now". Both the popover row and the menubar segment derive their
/// rendering from an instance of this struct, so the two views can never
/// disagree on whether a window is unknown. Any new surface that shows a
/// time-window metric must go through this type as well.
///
/// IMPORTANT semantic: a usage percent is intrinsically tied to its window.
/// "48% of the last 5 hours" means something; "48% of an unknown timeframe"
/// does not. When `resetAt` is missing, unparseable, or already elapsed, the
/// percent cannot be interpreted either — so it MUST be rendered as "???"
/// along with the remaining time. This is enforced at the struct boundary:
/// `actualFraction` collapses to 0 and `isUnknown` is exposed for the views
/// to mask both numbers behind "???".
public struct TimeWindowVisualState: Sendable, Equatable {
    /// True when `resetAt` is absent, unparseable, or already elapsed.
    /// In that state both the percent and the remaining time must surface
    /// as "???" — without a known window, the percent has no denominator
    /// the user can reason about.
    public let isUnknown: Bool
    /// Usage fraction in 0...1. Zero when `isUnknown` is true so callers
    /// can paint an empty gauge without re-checking the flag.
    public let actualFraction: Double
    /// Elapsed-time fraction of the window in 0...1. Zero when `isUnknown`.
    /// Named `elapsedFraction` to avoid shadowing the free function
    /// `theoreticalFraction(resetAt:windowDuration:now:)`.
    public let elapsedFraction: Double
    /// Severity tier when comparable, `nil` when the window is unknown or
    /// hasn't accumulated enough elapsed time for a ratio.
    public let tier: ConsumptionTier?

    public init(resetAt: ISODate?, windowDuration: DurationMinutes, usagePercent: UsagePercent, now: Date) {
        if let resetAt, let resetDate = resetAt.date, now <= resetDate {
            self.isUnknown = false
            self.actualFraction = Double(usagePercent.rawValue) / 100.0
            let elapsed = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
            self.elapsedFraction = elapsed
            self.tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: elapsed)
                .map(consumptionTier(ratio:))
        } else {
            self.isUnknown = true
            self.actualFraction = 0
            self.elapsedFraction = 0
            self.tier = nil
        }
    }
}

// MARK: - Entry sorting

extension Array where Element == VendorUsageEntry {
    /// Sorted by vendor name, then active-first within each vendor, then account name.
    public func sortedForDisplay() -> [VendorUsageEntry] {
        sorted { lhs, rhs in
            if lhs.vendor.rawValue != rhs.vendor.rawValue {
                return lhs.vendor.rawValue < rhs.vendor.rawValue
            }
            if lhs.isActive != rhs.isActive {
                return lhs.isActive
            }
            return lhs.account.rawValue < rhs.account.rawValue
        }
    }

    /// Returns entries that are not in the ignored set.
    public func excluding(ignoredAccounts: [IgnoredAccount]) -> [VendorUsageEntry] {
        let ignoredSet = Set(ignoredAccounts)
        return filter { !ignoredSet.contains(IgnoredAccount(vendor: $0.vendor, account: $0.account)) }
    }

    /// Set of vendors that appear more than once in the array.
    public func vendorsWithMultipleAccounts() -> Set<Vendor> {
        var counts: [Vendor: Int] = [:]
        for entry in self {
            counts[entry.vendor, default: 0] += 1
        }
        return Set(counts.filter { $0.value > 1 }.keys)
    }
}

import AppKit
import AIUsagesTrackersLib

/// Rasterises the full menu bar label into a non-template `NSImage`.
/// MenuBarExtra's label was unusable: template tinting stripped the per-tier
/// dot colors, and mixed HStacks silently truncated segments past the first.
/// With a custom `NSStatusItem`, we control `isTemplate = false` so hues
/// survive and we pick the text color from the status button's effective
/// appearance (which tracks the menu bar, not the app).
@MainActor
enum MenuBarLabelRenderer {
    private static let font: NSFont = .menuBarFont(ofSize: 0)
    private static let dot = "● "
    private static let horizontalPadding: CGFloat = 4
    private static let height: CGFloat = 18
    static let unconfiguredCallToAction = "Configure AI Metrics"

    static func render(
        segments: [MenuBarSegment],
        separator: String,
        fallbackText: String,
        isDarkMenuBar: Bool,
        isUnconfigured: Bool = false
    ) -> NSImage {
        let textColor: NSColor = isDarkMenuBar ? .white : .black
        let attributed: NSAttributedString
        if isUnconfigured && segments.isEmpty {
            attributed = unconfiguredAttributedString(textColor: textColor)
        } else {
            attributed = attributedString(
                segments: segments,
                separator: separator,
                fallbackText: fallbackText,
                textColor: textColor
            )
        }
        let textSize = attributed.size()
        let width = ceil(textSize.width) + horizontalPadding * 2
        let size = NSSize(width: max(width, 1), height: height)
        let image = NSImage(size: size)
        image.lockFocus()
        let textY = (height - ceil(textSize.height)) / 2
        attributed.draw(at: NSPoint(x: horizontalPadding, y: textY))
        image.unlockFocus()
        image.isTemplate = false
        return image
    }

    private static func unconfiguredAttributedString(textColor: NSColor) -> NSAttributedString {
        let result = NSMutableAttributedString()
        let gear = NSImage(systemSymbolName: "gearshape", accessibilityDescription: nil)
        if let gear {
            let configured = gear.withSymbolConfiguration(
                NSImage.SymbolConfiguration(pointSize: font.pointSize, weight: .regular)
            ) ?? gear
            configured.isTemplate = true
            let tinted = NSImage(size: configured.size, flipped: false) { rect in
                configured.draw(in: rect)
                textColor.set()
                rect.fill(using: .sourceAtop)
                return true
            }
            tinted.isTemplate = false
            let attachment = NSTextAttachment()
            attachment.image = tinted
            attachment.bounds = CGRect(
                x: 0,
                y: -1,
                width: tinted.size.width,
                height: tinted.size.height
            )
            result.append(NSAttributedString(attachment: attachment))
            result.append(NSAttributedString(
                string: " ",
                attributes: [.font: font, .foregroundColor: textColor]
            ))
        }
        result.append(NSAttributedString(
            string: unconfiguredCallToAction,
            attributes: [.font: font, .foregroundColor: textColor]
        ))
        return result
    }

    private static func attributedString(
        segments: [MenuBarSegment],
        separator: String,
        fallbackText: String,
        textColor: NSColor
    ) -> NSAttributedString {
        guard !segments.isEmpty else {
            return NSAttributedString(
                string: fallbackText,
                attributes: [.font: font, .foregroundColor: textColor]
            )
        }
        let result = NSMutableAttributedString()
        for (index, segment) in segments.enumerated() {
            if index > 0, !separator.isEmpty {
                result.append(NSAttributedString(
                    string: separator,
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if let vendor = segment.vendorIcon,
               let icon = VendorBrandingResolver.tintedNSImage(for: vendor, height: font.capHeight) {
                let attachment = NSTextAttachment()
                attachment.image = icon
                let pad = VendorBrandingResolver.iconGlowPadding
                attachment.bounds = CGRect(
                    x: -pad,
                    y: -pad,
                    width: icon.size.width,
                    height: icon.size.height
                )
                result.append(NSAttributedString(attachment: attachment))
                result.append(NSAttributedString(
                    string: "\u{2009}",
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if let warning = segment.outageWarningText, !warning.isEmpty {
                result.append(NSAttributedString(
                    string: warning + "\u{2009}",
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if segment.showDot {
                let dotColor = segment.tier?.nsColor ?? textColor
                result.append(NSAttributedString(
                    string: dot,
                    attributes: [.font: font, .foregroundColor: dotColor]
                ))
            }
            result.append(NSAttributedString(
                string: segment.text,
                attributes: [.font: font, .foregroundColor: textColor]
            ))
        }
        return result
    }
}

import SwiftUI
import AppKit
import AIUsagesTrackersLib

extension ConsumptionTier {
    /// SwiftUI color for this severity tier.
    /// System colors adapt to light/dark mode automatically.
    var color: Color {
        Color(nsColor)
    }

    /// AppKit color used when rasterising the menu bar label into an `NSImage`.
    /// Mirrors `color` but stays in AppKit so it can feed `NSAttributedString`.
    var nsColor: NSColor {
        switch self {
        case .comfortable: return .systemGreen
        case .onTrack:     return .systemBlue
        case .approaching: return .systemYellow
        case .over:        return .systemOrange
        case .critical:    return .systemRed
        // Purple keeps the bar visible in both light and dark mode; .labelColor (black in light
        // mode) made the theoretical-consumption tick invisible against the overflow background.
        case .exhausted:   return NSColor(red: 0x7B / 255.0, green: 0x2F / 255.0, blue: 0xBE / 255.0, alpha: 1.0)
        }
    }
}

