import SwiftUI
import AppKit
import AIUsagesTrackersLib

struct MenubarHintSettingsView: View {
    let preferences: any AppPreferences

    @Environment(\.colorScheme) private var colorScheme

    var body: some View {
        if let store = AppDelegate.sharedStore {
            MenubarHintContent(
                preferences: preferences,
                store: store,
                isDark: colorScheme == .dark
            )
        } else {
            ContentUnavailableView(
                "Settings loading",
                systemImage: "hourglass",
                description: Text("Usage data is initializing. Close and reopen Settings.")
            )
        }
    }
}

// MARK: - Content

private struct MenubarHintContent: View {
    let preferences: any AppPreferences
    @Bindable var store: UsageStore
    let isDark: Bool

    @State private var pendingDelete: UUID?

    var body: some View {
        VStack(alignment: .leading, spacing: 0) {
            previewPanel
            Divider()
            segmentsPanel
        }
        .confirmationDialog(
            deleteConfirmationTitle,
            isPresented: deleteConfirmationBinding,
            titleVisibility: .visible
        ) {
            Button("Delete segment", role: .destructive) {
                if let id = pendingDelete {
                    delete(segmentID: id)
                }
                pendingDelete = nil
            }
            Button("Cancel", role: .cancel) {
                pendingDelete = nil
            }
        } message: {
            Text("This segment will no longer appear in the menu bar.")
        }
    }

    // MARK: Preview

    @ViewBuilder
    private var previewPanel: some View {
        VStack(alignment: .leading, spacing: 8) {
            Text("Preview")
                .font(.caption)
                .foregroundStyle(.secondary)
                .textCase(.uppercase)
            HStack {
                Image(nsImage: MenuBarLabelRenderer.render(
                    segments: store.menuBarSegments,
                    separator: preferences.menuBarSeparator,
                    fallbackText: store.menuBarText,
                    isDarkMenuBar: isDark
                ))
                Spacer()
            }
            .padding(8)
            .background(
                RoundedRectangle(cornerRadius: 6)
                    .fill(isDark ? Color.black.opacity(0.6) : Color.white)
            )
            .overlay(
                RoundedRectangle(cornerRadius: 6)
                    .stroke(Color.secondary.opacity(0.3), lineWidth: 1)
            )

            HStack(spacing: 6) {
                Text("Separator")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                TextField("", text: Binding(
                    get: { preferences.menuBarSeparator },
                    set: { preferences.menuBarSeparator = $0 }
                ))
                .textFieldStyle(.roundedBorder)
                .frame(width: 80)
            }
        }
        .padding(16)
    }

    // MARK: Segments list

    @ViewBuilder
    private var segmentsPanel: some View {
        if AppDelegate.sharedPreferences.menuBarSegments.isEmpty {
            emptyState
        } else {
            segmentsList
        }
    }

    private var emptyState: some View {
        VStack(spacing: 12) {
            Spacer(minLength: 24)
            Text("No segments configured")
                .font(.headline)
            Text("The menu bar will show \"--\" until you add a segment.")
                .font(.caption)
                .foregroundStyle(.secondary)
            Button {
                addSegment()
            } label: {
                Label("Add your first segment", systemImage: "plus")
            }
            .disabled(availableVendors.isEmpty)
            Spacer(minLength: 24)
        }
        .frame(maxWidth: .infinity)
        .padding(16)
    }

    private var segmentsList: some View {
        VStack(spacing: 0) {
            HStack {
                Text("Segments")
                    .font(.headline)
                Spacer()
                Button {
                    addSegment()
                } label: {
                    Label("Add", systemImage: "plus")
                }
                .disabled(availableVendors.isEmpty)
            }
            .padding(.horizontal, 16)
            .padding(.top, 12)
            .padding(.bottom, 4)

            ScrollView {
                VStack(spacing: 0) {
                    ForEach(Array(AppDelegate.sharedPreferences.menuBarSegments.enumerated()), id: \.element.id) { index, segment in
                        SegmentCardView(
                            preferences: preferences,
                            store: store,
                            isDark: isDark,
                            segmentID: segment.id,
                            canMoveUp: index > 0,
                            canMoveDown: index < AppDelegate.sharedPreferences.menuBarSegments.count - 1,
                            onMoveUp: { move(from: index, to: index - 1) },
                            onMoveDown: { move(from: index, to: index + 2) },
                            onRequestDelete: { pendingDelete = segment.id }
                        )
                        Divider()
                    }
                }
                .padding(.horizontal, 16)
            }
        }
    }

    // MARK: Mutations

    private func addSegment() {
        let prefs = AppDelegate.sharedPreferences
        guard let vendor = availableVendors.first else { return }
        let defaultMetricName = firstAvailableMetricName(for: vendor, account: .currentlyActive)
            ?? ""
        let display: SegmentDisplay = makeDefaultDisplay(
            vendor: vendor,
            account: .currentlyActive,
            metricName: defaultMetricName
        )
        let new = MenuBarSegmentConfig(
            vendor: vendor,
            account: .currentlyActive,
            metricName: defaultMetricName,
            display: display
        )
        prefs.menuBarSegments.append(new)
    }

    private func delete(segmentID: UUID) {
        let prefs = AppDelegate.sharedPreferences
        prefs.menuBarSegments.removeAll { $0.id == segmentID }
    }

    private func move(from source: Int, to destination: Int) {
        let prefs = AppDelegate.sharedPreferences
        var segments = prefs.menuBarSegments
        guard source >= 0, source < segments.count else { return }
        let dest = max(0, min(destination, segments.count))
        segments.move(fromOffsets: IndexSet(integer: source), toOffset: dest)
        prefs.menuBarSegments = segments
    }

    // MARK: Helpers

    private var availableVendors: [Vendor] {
        Array(Set(store.entries.map(\.vendor))).sorted { $0.rawValue < $1.rawValue }
    }

    private func firstAvailableMetricName(
        for vendor: Vendor,
        account: AccountSelection
    ) -> String? {
        let entry = resolveEntry(vendor: vendor, account: account, in: store.entries)
        return entry?.metrics.compactMap(metricName).first
    }

    private func makeDefaultDisplay(
        vendor: Vendor,
        account: AccountSelection,
        metricName: String
    ) -> SegmentDisplay {
        let entry = resolveEntry(vendor: vendor, account: account, in: store.entries)
        let metric = entry?.metrics.first(where: { SegmentEditingHelpers.metricName($0) == metricName })
        switch metric {
        case .some(.payAsYouGo):
            return .payAsYouGo
        case .some(.timeWindow), .some(.unknown), .none:
            return .timeWindow(TimeWindowDisplay(letter: MenuBarMetricLetter.defaultLetter(for: metricName)))
        }
    }

    private func resolveEntry(
        vendor: Vendor,
        account: AccountSelection,
        in entries: [VendorUsageEntry]
    ) -> VendorUsageEntry? {
        let vendorEntries = entries.filter { $0.vendor == vendor }
        switch account {
        case .currentlyActive:
            return vendorEntries.first(where: { $0.isActive })
        case .specific(let email):
            return vendorEntries.first(where: { $0.account == email })
        }
    }

    private func metricName(_ metric: UsageMetric) -> String? {
        SegmentEditingHelpers.metricName(metric)
    }

    private var deleteConfirmationBinding: Binding<Bool> {
        Binding(
            get: { pendingDelete != nil },
            set: { if !$0 { pendingDelete = nil } }
        )
    }

    private var deleteConfirmationTitle: String {
        guard let id = pendingDelete,
              let segment = AppDelegate.sharedPreferences.menuBarSegments.first(where: { $0.id == id }) else {
            return "Delete segment?"
        }
        return "Delete \(segment.metricName) segment?"
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// Displays a time-window metric: name, gauge bar with theoretical marker,
/// percentage, remaining time, and next reset date.
struct TimeWindowMetricRow: View {
    let name: String
    let resetAt: ISODate?
    let windowDuration: DurationMinutes
    let usagePercent: UsagePercent

    var body: some View {
        // TimelineView re-renders every minute so remaining time and theoretical
        // consumption stay accurate even when no network refresh occurs.
        TimelineView(.periodic(from: .now, by: 60)) { context in
            content(now: context.date)
        }
    }

    @ViewBuilder
    private func content(now: Date) -> some View {
        // Single source of truth shared with MenuBarSegmentResolver — see
        // TimeWindowVisualState. Do NOT recompute isUnknown / tier locally.
        let state = TimeWindowVisualState(
            resetAt: resetAt,
            windowDuration: windowDuration,
            usagePercent: usagePercent,
            now: now
        )

        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(name)
                    .font(.system(size: 11, weight: .medium))
                    .foregroundStyle(.secondary)
                Spacer()
                Text(state.isUnknown ? "???" : "\(usagePercent.rawValue)%")
                    .font(.system(size: 11, weight: .semibold).monospacedDigit())
            }

            GaugeBar(
                actual: state.actualFraction,
                theoretical: state.elapsedFraction,
                tier: state.tier
            )

            HStack {
                Text(state.isUnknown ? "???" : formatRemainingTime(resetAt: resetAt!, now: now))
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.secondary)
                Spacer()
                Text(state.isUnknown ? "resets ???" : "resets \(formatResetDate(resetAt!, now: now))")
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
            }
        }
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// A horizontal progress bar with an actual fill and a theoretical consumption marker.
/// The theoretical marker is a thin vertical tick showing expected consumption based on elapsed time.
struct GaugeBar: View {
    let actual: Double
    let theoretical: Double
    var tier: ConsumptionTier?

    private static let barHeight: CGFloat = 6
    private static let markerWidth: CGFloat = 2.5
    private static let cornerRadius: CGFloat = 3

    var body: some View {
        GeometryReader { geo in
            let width = geo.size.width

            ZStack(alignment: .leading) {
                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(.quaternary)

                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(fillColor)
                    .frame(width: width * clamp(actual))

                // Skip marker when no window data — avoids a tick pinned to the left edge at 0.
                if theoretical > 0 {
                    RoundedRectangle(cornerRadius: Self.markerWidth / 2)
                        .fill(.primary)
                        .frame(width: Self.markerWidth, height: Self.barHeight + 4)
                        .offset(x: width * clamp(theoretical) - Self.markerWidth / 2)
                }
            }
        }
        .frame(height: Self.barHeight)
    }

    private var fillColor: Color {
        if let tier { return tier.color }
        return .accentColor
    }

    private func clamp(_ value: Double) -> CGFloat {
        CGFloat(min(max(value, 0), 1))
    }
}

import Foundation

// MARK: - AccountSelection

/// Which account a segment targets. `.currentlyActive` re-resolves at render time
/// so the segment tracks whichever Claude account is currently active.
public enum AccountSelection: Codable, Equatable, Hashable, Sendable {
    case currentlyActive
    case specific(AccountEmail)

    private enum CodingKeys: String, CodingKey {
        case kind, email
    }

    private enum Kind: String, Codable {
        case currentlyActive = "currently-active"
        case specific
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .currentlyActive:
            self = .currentlyActive
        case .specific:
            let email = try container.decode(AccountEmail.self, forKey: .email)
            self = .specific(email)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .currentlyActive:
            try container.encode(Kind.currentlyActive, forKey: .kind)
        case .specific(let email):
            try container.encode(Kind.specific, forKey: .kind)
            try container.encode(email, forKey: .email)
        }
    }
}

// MARK: - SegmentDisplay

/// Variant-dependent display options. `timeWindow` carries four independent
/// toggles plus the letter shown when `showLetter` is on; `payAsYouGo` has no
/// options — the rendered text is always "amount currency".
public enum SegmentDisplay: Codable, Equatable, Hashable, Sendable {
    case timeWindow(TimeWindowDisplay)
    case payAsYouGo

    private enum CodingKeys: String, CodingKey {
        case kind, timeWindow
    }

    private enum Kind: String, Codable {
        case timeWindow = "time-window"
        case payAsYouGo = "pay-as-you-go"
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .timeWindow:
            let tw = try container.decode(TimeWindowDisplay.self, forKey: .timeWindow)
            self = .timeWindow(tw)
        case .payAsYouGo:
            self = .payAsYouGo
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .timeWindow(let tw):
            try container.encode(Kind.timeWindow, forKey: .kind)
            try container.encode(tw, forKey: .timeWindow)
        case .payAsYouGo:
            try container.encode(Kind.payAsYouGo, forKey: .kind)
        }
    }
}

public enum UsagePercentDisplayMode: String, Codable, Equatable, Hashable, CaseIterable, Sendable {
    case consumed
    case remaining
}

public struct TimeWindowDisplay: Codable, Equatable, Hashable, Sendable {
    public var showDot: Bool
    public var showLetter: Bool
    public var letter: String
    public var showPercent: Bool
    public var percentDisplayMode: UsagePercentDisplayMode
    public var showReset: Bool
    public var hideResetMinutesWhenOverOneDay: Bool
    public var showVendorIcon: Bool

    public init(
        showDot: Bool = true,
        showLetter: Bool = true,
        letter: String = "",
        showPercent: Bool = true,
        percentDisplayMode: UsagePercentDisplayMode = .consumed,
        showReset: Bool = true,
        hideResetMinutesWhenOverOneDay: Bool = true,
        showVendorIcon: Bool = false
    ) {
        self.showDot = showDot
        self.showLetter = showLetter
        self.letter = letter
        self.showPercent = showPercent
        self.percentDisplayMode = percentDisplayMode
        self.showReset = showReset
        self.hideResetMinutesWhenOverOneDay = hideResetMinutesWhenOverOneDay
        self.showVendorIcon = showVendorIcon
    }

    private enum CodingKeys: String, CodingKey {
        case showDot, showLetter, letter, showPercent, percentDisplayMode, showReset
        case hideResetMinutesWhenOverOneDay, showVendorIcon
    }

    public init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        showDot = try c.decode(Bool.self, forKey: .showDot)
        showLetter = try c.decode(Bool.self, forKey: .showLetter)
        letter = try c.decode(String.self, forKey: .letter)
        showPercent = try c.decode(Bool.self, forKey: .showPercent)
        percentDisplayMode = try c.decodeIfPresent(
            UsagePercentDisplayMode.self,
            forKey: .percentDisplayMode
        ) ?? .consumed
        showReset = try c.decode(Bool.self, forKey: .showReset)
        hideResetMinutesWhenOverOneDay = try c.decodeIfPresent(
            Bool.self,
            forKey: .hideResetMinutesWhenOverOneDay
        ) ?? true
        showVendorIcon = try c.decodeIfPresent(Bool.self, forKey: .showVendorIcon) ?? false
    }
}

// MARK: - MenuBarSegmentConfig

/// A user-configured menu bar segment: which metric to read (vendor/account/metric)
/// and how to display it. Persisted as JSON in UserDefaults.
public struct MenuBarSegmentConfig: Codable, Equatable, Hashable, Sendable, Identifiable {
    public let id: UUID
    public var vendor: Vendor
    public var account: AccountSelection
    public var metricName: String
    public var display: SegmentDisplay
    /// When true and the segment's vendor currently has an active outage,
    /// `outageWarningText` is rendered in the menu bar immediately after the
    /// vendor icon (or at the segment's start when no icon is shown).
    public var showOutageWarning: Bool
    /// Short label rendered while the segment's vendor has an active outage.
    /// Defaults to "⚠️". Ignored when `showOutageWarning` is false.
    public var outageWarningText: String

    public static let defaultOutageWarningText: String = "⚠️"

    public init(
        id: UUID = UUID(),
        vendor: Vendor,
        account: AccountSelection,
        metricName: String,
        display: SegmentDisplay,
        showOutageWarning: Bool = false,
        outageWarningText: String = MenuBarSegmentConfig.defaultOutageWarningText
    ) {
        self.id = id
        self.vendor = vendor
        self.account = account
        self.metricName = metricName
        self.display = display
        self.showOutageWarning = showOutageWarning
        self.outageWarningText = outageWarningText
    }

    private enum CodingKeys: String, CodingKey {
        case id, vendor, account, metricName, display
        case showOutageWarning, outageWarningText
    }

    public init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        id = try c.decode(UUID.self, forKey: .id)
        vendor = try c.decode(Vendor.self, forKey: .vendor)
        account = try c.decode(AccountSelection.self, forKey: .account)
        metricName = try c.decode(String.self, forKey: .metricName)
        display = try c.decode(SegmentDisplay.self, forKey: .display)
        showOutageWarning = try c.decodeIfPresent(Bool.self, forKey: .showOutageWarning) ?? false
        outageWarningText = try c.decodeIfPresent(String.self, forKey: .outageWarningText)
            ?? MenuBarSegmentConfig.defaultOutageWarningText
    }

    public func encode(to encoder: Encoder) throws {
        var c = encoder.container(keyedBy: CodingKeys.self)
        try c.encode(id, forKey: .id)
        try c.encode(vendor, forKey: .vendor)
        try c.encode(account, forKey: .account)
        try c.encode(metricName, forKey: .metricName)
        try c.encode(display, forKey: .display)
        try c.encode(showOutageWarning, forKey: .showOutageWarning)
        try c.encode(outageWarningText, forKey: .outageWarningText)
    }
}

// MARK: - Default letters

/// Maps known metric names to their canonical menu bar letter. When unknown,
/// the first character of the metric name (uppercased) is used as default.
public enum MenuBarMetricLetter {
    private static let knownAbbreviations: [String: String] = [
        "5h sessions (all models)": "S",
        "Weekly (all models)": "W",
    ]

    public static func defaultLetter(for metricName: String) -> String {
        if let known = knownAbbreviations[metricName] {
            return known
        }
        return String(metricName.prefix(1)).uppercased()
    }
}

